import './InlineEditModal.scss';

import type { FC } from 'react';
import React, { useCallback, useLayoutEffect, useState } from 'react';
import ReactDOM from 'react-dom';

import type { InlineEditModalProps } from './InlineEditModal.types';

export const PopoverContext = React.createContext({
	applicationRootElementId: 'root',
});

export const InlineEditModal: FC<InlineEditModalProps> = ({ contentRect, children }) => {
	const [coords, setCoords] = useState<{ x: number; y: number }>({
		x: 0,
		y: 0,
	});
	const { applicationRootElementId } = React.useContext(PopoverContext);
	const MAX_HEIGHT = 56;
	const getXCoords = useCallback((): number => {
		// Because property 'ref' does not exist on type ReactElement by default.
		const modalObj = children.ref.current;
		const bodyCoords = document.querySelector('body')?.getBoundingClientRect();

		if (contentRect && bodyCoords && modalObj) {
			const modalCoords = modalObj.getBoundingClientRect();

			/**
        Если по ширине вылазим за правый край, смещаемся влево на ширину формы
      */
			return bodyCoords.width - contentRect?.x < modalCoords.width
				? bodyCoords.width - modalCoords.width
				: contentRect?.x;
		}
		return 0;
	}, [children, contentRect]);

	const getYCoords = useCallback((): number => {
		if (contentRect) {
			return contentRect?.y - (MAX_HEIGHT / 2 - contentRect?.height / 2);
		}
		return 0;
	}, [contentRect]);

	useLayoutEffect(() => {
		setCoords({ x: getXCoords(), y: getYCoords() });
	}, [contentRect, getXCoords, getYCoords]);

	const mount = document.querySelector('#' + applicationRootElementId);

	if (!mount) {
		throw new Error(`Application root element with ID "${applicationRootElementId}" not found`);
	}

	const modal = (
		<div data-testid="InlineEditModal" className="dsb_inline-edit-modal">
			<div
				className="dsb_inline-edit-modal_positioner"
				style={{
					position: 'absolute',
					left: `${coords.x}px`,
					top: `${coords.y}px`,
				}}
			>
				{children}
			</div>
		</div>
	);

	return ReactDOM.createPortal(modal, mount);
};
